// src/fonts/manager/sources.ts
async function tryFetchFontBuffer(url) {
  try {
    const response = await fetch(url);
    if (response.ok)
      return response.arrayBuffer();
  } catch {}
  return null;
}
async function tryLocalFontBuffer(matchers) {
  const globalAccess = globalThis;
  const nav = globalAccess.navigator ?? navigator;
  const queryLocalFonts = typeof globalAccess.queryLocalFonts === "function" ? globalAccess.queryLocalFonts.bind(globalAccess) : typeof nav.queryLocalFonts === "function" ? nav.queryLocalFonts.bind(nav) : null;
  if (!queryLocalFonts)
    return null;
  const normalizedMatchers = matchers.map((matcher) => matcher.toLowerCase()).filter(Boolean);
  if (!normalizedMatchers.length)
    return null;
  const queryPermission = nav.permissions?.query;
  if (queryPermission) {
    try {
      const status = await queryPermission({ name: "local-fonts" });
      if (status?.state === "denied")
        return null;
    } catch {}
  }
  try {
    const fonts = await queryLocalFonts();
    const match = fonts.find((font) => {
      const name = `${font.family ?? ""} ${font.fullName ?? ""} ${font.postscriptName ?? ""}`.toLowerCase();
      return normalizedMatchers.some((matcher) => name.includes(matcher));
    });
    if (match) {
      const blob = await match.blob();
      return blob.arrayBuffer();
    }
  } catch (err) {
    console.warn("queryLocalFonts failed", err);
  }
  return null;
}
async function loadPrimaryFontBuffer(localMatchers, fallbackUrl, fallbackLocalMatchers) {
  const nerdLocal = await tryLocalFontBuffer(localMatchers);
  if (nerdLocal)
    return nerdLocal;
  const buffer = await tryFetchFontBuffer(fallbackUrl);
  if (buffer)
    return buffer;
  const local = await tryLocalFontBuffer(fallbackLocalMatchers);
  if (local)
    return local;
  throw new Error("Unable to load primary font.");
}
async function loadFallbackFontBuffers(sources) {
  const results = [];
  for (const source of sources) {
    const buffer = await tryFetchFontBuffer(source.url);
    if (buffer) {
      results.push({ name: source.name, buffer });
      continue;
    }
    if (source.matchers && source.matchers.length) {
      const local = await tryLocalFontBuffer(source.matchers);
      if (local)
        results.push({ name: source.name, buffer: local });
    }
  }
  return results;
}

