    glyphDataLinearByFont,
    glyphQueueByFont,
    overlayGlyphDataNearestByFont,
    overlayGlyphDataLinearByFont,
    overlayGlyphQueueByFont,
    neededGlyphIdsByFont,
    neededGlyphMetaByFont,
    scaleByFont,
    bitmapScaleByFont,
    baselineAdjustByFont,
    nerdMetrics,
    getGlyphQueue,
    getOverlayGlyphQueue,
    getGlyphSet
